// POST /authorize - Handle user login and consent
app.post('/authorize', (req, res) => {
  const { client_id, redirect_uri, scope, state, username, password, consent, response_type } = req.body;

  // Validate client again
  const clientValidation = validateClient(client_id, redirect_uri);
  if (!clientValidation.valid) {
    return res.status(400).send(`
      <html><body>
        <h1>Error</h1>
        <p>${clientValidation.error}</p>
      </body></html>
    `);
  }

  const redirectUrl = new URL(redirect_uri);

  // Handle denial
  if (consent === 'deny') {
    redirectUrl.searchParams.set('error', 'access_denied');
    redirectUrl.searchParams.set('error_description', 'The user denied the authorization request');
    if (state) redirectUrl.searchParams.set('state', state);
    return res.redirect(redirectUrl.toString());
  }

  // Authenticate user
  const user = users[username];
  if (!user || user.password !== password) {
    return res.status(401).send(`
      <html>
      <head><title>Authentication Failed</title>
        <style>
          body { font-family: Arial, sans-serif; max-width: 500px; margin: 50px auto; padding: 20px; }
          .error { color: #dc3545; }
          a { color: #0066cc; }
        </style>
      </head>
      <body>
        <h1 class="error">Authentication Failed</h1>
        <p>Invalid username or password. Please try again.</p>
        <a href="/authorize?response_type=${response_type}&client_id=${client_id}&redirect_uri=${encodeURIComponent(redirect_uri)}&scope=${encodeURIComponent(scope)}&state=${encodeURIComponent(state || '')}">Back to login</a>
      </body>
      </html>
    `);
  }

  // Generate authorization code
  const code = generateCode();
  const expiresAt = Date.now() + 10 * 60 * 1000; // 10 minutes

  authorizationCodes[code] = {
    client_id,
    redirect_uri,
    user: username,
    scope: scope || 'read',
    expires_at: expiresAt,
    used: false
  };

  console.log(`[AUTH] Authorization code issued for user "${username}", client "${client_id}", scope "${scope}"`);

  // Redirect back to client with code
  redirectUrl.searchParams.set('code', code);
  if (state) redirectUrl.searchParams.set('state', state);

  return res.redirect(redirectUrl.toString());
});

// POST /token - Token endpoint
app.post('/token', (req, res) => {
  const { grant_type } = req.body;

  if (grant_type === 'authorization_code') {
    return handleAuthorizationCodeGrant(req, res);
  } else if (grant_type === 'refresh_token') {
    return handleRefreshTokenGrant(req, res);
  } else {
    return res.status(400).json({
      error: 'unsupported_grant_type',
      error_description: 'Only authorization_code and refresh_token grant types are supported'
    });
  }
});

function authenticateClient(req) {
  // Check Authorization header (Basic auth)
  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString();
    const [client_id, client_secret] = decoded.split(':');
    return { client_id, client_secret };
  }

  // Fall back to body parameters
  return {
    client_id: req.body.client_id,
    client_secret: req.body.client_secret
  };
}

function handleAuthorizationCodeGrant(req, res) {
  const { code, redirect_uri } = req.body;
  const { client_id, client_secret } = authenticateClient(req);

  // Validate client credentials
  const client = clients[client_id];
  if (!client) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Unknown client'
    });
  }

  if (client.client_secret !== client_secret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Invalid client credentials'
    });
  }

  // Validate authorization code
  if (!code || !authorizationCodes[code]) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Invalid authorization code'
    });
  }

  const authCode = authorizationCodes[code];

  // Check if code has been used (prevent replay)
  if (authCode.used) {
    // Revoke all tokens issued with this code (security measure)
    console.log(`[SECURITY] Authorization code reuse detected for client "${client_id}"`);
    delete authorizationCodes[code];
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code has already been used'
    });
  }

  // Check expiration
  if (Date.now() > authCode.expires_at) {
    delete authorizationCodes[code];
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code has expired'
    });
  }

  // Verify client_id matches
  if (authCode.client_id !== client_id) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code was not issued to this client'
    });
  }

  // Verify redirect_uri matches
  if (authCode.redirect_uri !== redirect_uri) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'redirect_uri does not match the one used in the authorization request'
    });
  }

  // Mark code as used
  authCode.used = true;

  // Generate tokens
  const accessToken = generateToken();
  const refreshToken = generateToken();
  const expiresIn = 3600; // 1 hour

  accessTokens[accessToken] = {
    client_id,
    user: authCode.user,
    scope: authCode.scope,
    expires_at: Date.now() + expiresIn * 1000
  };

  refreshTokens[refreshToken] = {
    client_id,
    user: authCode.user,
    scope: authCode.scope
  };

  console.log(`[TOKEN] Access token issued for user "${authCode.user}", client "${client_id}"`);

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: expiresIn,
    refresh_token: refreshToken,
    scope: authCode.scope
  });
}

function handleRefreshTokenGrant(req, res) {
  const { refresh_token, scope } = req.body;
  const { client_id, client_secret } = authenticateClient(req);

  // Validate client credentials
  const client = clients[client_id];
  if (!client || client.client_secret !== client_secret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Invalid client credentials'
    });
  }

  // Validate refresh token
  if (!refresh_token || !refreshTokens[refresh_token]) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Invalid refresh token'
    });
  }

  const storedRefreshToken = refreshTokens[refresh_token];

  // Verify client_id matches
  if (storedRefreshToken.client_id !== client_id) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Refresh token was not issued to this client'
    });
  }

  // Handle scope narrowing (requested scope must be subset of original)
  const effectiveScope = scope || storedRefreshToken.scope;
  if (scope) {
    const originalScopes = storedRefreshToken.scope.split(' ');
    const requestedScopes = scope.split(' ');
    const isSubset = requestedScopes.every(s => originalScopes.includes(s));
    if (!isSubset) {
      return res.status(400).json({
        error: 'invalid_scope',
        error_description: 'Requested scope exceeds the scope of the original grant'
      });
    }
  }

  // Rotate refresh token
  delete refreshTokens[refresh_token];

  // Generate new tokens
  const newAccessToken = generateToken();
  const newRefreshToken = generateToken();
  const expiresIn = 3600;

  accessTokens[newAccessToken] = {
    client_id,
    user: storedRefreshToken.user,
    scope: effectiveScope,
    expires_at: Date.now() + expiresIn * 1000
  };

  refreshTokens[newRefreshToken] = {
    client_id,
    user: storedRefreshToken.user,
    scope: storedRefreshToken.scope // Keep original scope for future refreshes
  };

  console.log(`[TOKEN] Access token refreshed for user "${storedRefreshToken.user}", client "${client_id}"`);

  res.json({
    access_token: newAccessToken,
    token_type: 'Bearer',
    expires_in: expiresIn,
    refresh_token: newRefreshToken,
    scope: effectiveScope
  });
}

// Token introspection endpoint (RFC 7662)
app.post('/introspect', (req, res) => {
  const { client_id, client_secret } = authenticateClient(req);
  const client = clients[client_id];
  if (!client || client.client_secret !== client_secret) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  const { token } = req.body;

  if (!token || !accessTokens[token]) {
    return res.json({ active: false });
  }

  const tokenData = accessTokens[token];

  if (Date.now() > tokenData.expires_at) {
    delete accessTokens[token];
    return res.json({ active: false });
  }

  res.json({
    active: true,
    scope: tokenData.scope,
    client_id: tokenData.client_id,
    username: tokenData.user,
    token_type: 'Bearer',
    exp: Math.floor(tokenData.expires_at / 1000),
    iat: Math.floor((tokenData.expires_at - 3600 * 1000) / 1000)
  });
});

// Token revocation endpoint (RFC 7009)
app.post('/revoke', (req, res) => {
  const { client_id, client_secret } = authenticateClient(req);
  const client = clients[client_id];
  if (!client || client.client_secret !== client_secret) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  const { token, token_type_hint } = req.body;

  if (token) {
    if (token_type_hint === 'refresh_token' || refreshTokens[token]) {
      delete refreshTokens[token];
    }
    if (token_type_hint === 'access_token' || accessTokens[token]) {
      delete accessTokens[token];
    }
    // If no hint, try both
    if (!token_type_hint) {
      delete refreshTokens[token];
      delete accessTokens[token];
    }
  }

  // Always return 200 per spec
  res.status(200).send();
});

// Protected resource endpoint (for testing)
app.get('/userinfo', (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Missing or invalid Bearer token' });
  }

  const token = authHeader.slice(7);
  const tokenData = accessTokens[token];

  if (!tokenData) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Token not found' });
  }

  if (Date.now() > tokenData.expires_at) {
    delete accessTokens[token];
    return res.status(401).json({ error: 'invalid_token', error_description: 'Token has expired' });
  }

  const user = users[tokenData.user];
  res.json({
    sub: tokenData.user,
    name: user.name,
    username: user.username,
    scope: tokenData.scope
  });
});

