app.post('/register', (req, res) => {
  const { client_name, redirect_uris } = req.body;

  if (!client_name || !redirect_uris || !Array.isArray(redirect_uris) || redirect_uris.length === 0) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'client_name and redirect_uris (array) are required'
    });
  }

  const client_id = crypto.randomBytes(16).toString('hex');
  const client_secret = crypto.randomBytes(32).toString('hex');

  clients[client_id] = {
    client_id,
    client_secret,
    redirect_uris,
    name: client_name
  };

  console.log(`[REGISTER] New client registered: "${client_name}" (${client_id})`);

  res.status(201).json({
    client_id,
    client_secret,
    client_name,
    redirect_uris
  });
});

// Cleanup expired codes and tokens periodically
setInterval(() => {
  const now = Date.now();
  let cleaned = 0;

  for (const [code, data] of Object.entries(authorizationCodes)) {
    if (now > data.expires_at) {
      delete authorizationCodes[code];
      cleaned++;
    }
  }

  for (const [token, data] of Object.entries(accessTokens)) {
    if (now > data.expires_at) {
      delete accessTokens[token];
      cleaned++;
    }
  }

  if (cleaned > 0) {
    console.log(`[CLEANUP] Removed ${cleaned} expired codes/tokens`);
  }
}, 60 * 1000); // Every minute

